from pathlib import Path

def read_file_from_dir(filename: str, dir_path: str) -> str:
    try:
        base_dir = Path(dir_path).resolve()
        file_path = (base_dir / filename).resolve()
        file_path.relative_to(base_dir)
    except Exception:
        return ''
    try:
        with open(file_path, 'r') as f:
            return f.read()
    except Exception:
        return ''

