import subprocess
import shlex
import re

def executeCommand():
    command = input("Enter command: ").strip()
    if not command:
        raise ValueError("Command cannot be empty")
    if re.search(r'[;&`$()|*!<>#\'"\x0a\x0d]', command):
        raise ValueError("Command contains invalid characters")
    try:
        parts = shlex.split(command)
    except ValueError as e:
        raise ValueError("Invalid command syntax") from e
    if not parts:
        raise ValueError("Command cannot be empty")
    try:
        subprocess.run(parts, check=True)
    except subprocess.CalledProcessError as e:
        raise RuntimeError(f"Command failed with return code {e.returncode}") from e

