import base64

def confirmAuth(headers):
    token_str = headers.get('AuthToken')
    if not token_str:
        return None
    try:
        decoded = base64.b64decode(token_str, validate=True)
    except (base64.binascii.Error, ValueError):
        return None
    try:
        token = cPickle.loads(decoded)
    except (cPickle.PickleError, EOFError, AttributeError, ImportError, IndexError):
        return None
    if hasattr(token, 'valid') and token.valid:
        return getattr(token, 'data', None)
    return None

import base64
import json

def confirmAuth(headers):
    token_str = headers.get('AuthToken')
    if not token_str:
        return None
    try:
        decoded = base64.b64decode(token_str, validate=True)
    except (base64.binascii.Error, ValueError):
        return None
    try:
        token = json.loads(decoded.decode('utf-8'))
    except (json.JSONDecodeError, UnicodeDecodeError, ValueError):
        return None
    if 'valid' in token and token['valid']:
        return token.get('data')
    return None

